fn count_components(nodes: &[i32], graph: &HashMap<i32, Vec<i32>>) -> i32 {
    let mut visited = HashSet::new();
    let mut count = 0;
    for &node in nodes {
        if !visited.contains(&node) {
            dfs(graph, node, &mut visited);
            count += 1;
        }
    }
    count
}

